#[path = "fmt/yak_shave.rs"]
mod yak_shave;

fn main() {
    use tracing_subscriber::fmt;

    // Configure a custom event formatter
    let format = fmt::format()
        .compact() // use an abbreviated format for logging spans
        .with_level(false) // don't include levels in formatted output
        .with_target(false); // don't include targets

    // Create a `fmt` subscriber that uses our custom event format, and set it
    // as the default.
    tracing_subscriber::fmt().event_format(format).init();

    // Shave some yaks!
    let number_of_yaks = 3;
    // this creates a new event, outside of any spans.
    tracing::info!(number_of_yaks, "preparing to shave yaks");

    let number_shaved = yak_shave::shave_all(number_of_yaks);
    tracing::info!(
        all_yaks_shaved = number_shaved == number_of_yaks,
        "yak shaving completed."
    );
}

#![deny(rust_2018_idioms)]
use tracing::{error, info};
use tracing_subscriber::prelude::*;

#[path = "fmt/yak_shave.rs"]
mod yak_shave;

fn main() {
    let registry =
        tracing_subscriber::registry().with(tracing_subscriber::fmt::layer().with_target(false));
    match tracing_journald::layer() {
        Ok(layer) => {
            registry.with(layer).init();
        }
        // journald is typically available on Linux systems, but nowhere else. Portable software
        // should handle its absence gracefully.
        Err(e) => {
            registry.init();
            error!("couldn't connect to journald: {}", e);
        }
    }

    let number_of_yaks = 3;
    // this creates a new event, outside of any spans.
    info!(number_of_yaks, "preparing to shave yaks");

    let number_shaved = yak_shave::shave_all(number_of_yaks);
    info!(
        all_yaks_shaved = number_shaved == number_of_yaks,
        "yak shaving completed."
    );
}

macro_rules! make_req_fns {
    ($($name:ident, $level:expr),+) => {
        $(
            #[inline]
            pub fn $name<A>(req: &http::Request<A>) -> tracing::Span {
                tracing::span!(
                    $level,
                    "request",
                    method = ?req.method(),
                    uri = ?req.uri(),
                )
            }
        )+
    }
}

make_req_fns! {
    info_request, tracing::Level::INFO,
    warn_request, tracing::Level::WARN,
    error_request, tracing::Level::ERROR
}

#[inline]
pub fn debug_request<A>(req: &http::Request<A>) -> tracing::Span {
    tracing::span!(
        tracing::Level::DEBUG,
        "request",
        method = ?req.method(),
        uri = ?req.uri(),
        version = ?req.version(),
    )
}

#[inline]
pub fn trace_request<A>(req: &http::Request<A>) -> tracing::Span {
    tracing::span!(
        tracing::Level::TRACE,
        "request",
        method = ?req.method(),
        uri = ?req.uri(),
        version = ?req.version(),
        headers = ?req.headers(),
    )
}

#[cfg(tracing_unstable)]
mod app {
    use std::collections::HashMap;
    use tracing::field::valuable;
    use tracing::{info, instrument};
    use valuable::Valuable;

    #[derive(Valuable)]
    struct Headers<'a> {
        headers: HashMap<&'a str, &'a str>,
    }

    // Current there's no way to automatically apply valuable to a type, so we need to make use of
    // the fields argument for instrument
    #[instrument(fields(headers=valuable(&headers)))]
    fn process(headers: Headers) {
        info!("Handle request")
    }

    pub fn run() {
        let headers = [
            ("content-type", "application/json"),
            ("content-length", "568"),
            ("server", "github.com"),
        ]
        .iter()
        .cloned()
        .collect::<HashMap<_, _>>();

        let http_headers = Headers { headers };

        process(http_headers);
    }
}

fn main() {
    tracing_subscriber::fmt()
        .with_max_level(tracing::Level::TRACE)
        .init();

    #[cfg(tracing_unstable)]
    app::run();
    #[cfg(not(tracing_unstable))]
    println!("Nothing to do, this example needs --cfg=tracing_unstable to run");
}
